mapper.select:
		select userid,username,paperid,papername,sum(myscore) myscore,ROUND(sum(case when myscore>0 then 1 else 0 end)/(sum(1)),2) accuracy from examrecord     
         1=1 ${ew.sqlSegment}
        group by userid,username,paperid,papername

SELECT ${params.xColumn}, ROUND(sum(${params.yColumn}),1) total FROM xueshengchengji
 1=1 ${ew.sqlSegment}
group by ${params.xColumn}
limit 10

select.if:
SELECT DATE_FORMAT(${params.xColumn},'%Y-%m-%d') ${params.xColumn}, sum(${params.yColumn}) total FROM xueshengchengji
 1=1 ${ew.sqlSegment}
group by DATE_FORMAT(${params.xColumn},'%Y-%m-%d')

SELECT DATE_FORMAT(${params.xColumn},'%Y-%m') ${params.xColumn}, sum(${params.yColumn}) total FROM xueshengchengji
 1=1 ${ew.sqlSegment}
group by DATE_FORMAT(${params.xColumn},'%Y-%m')

SELECT DATE_FORMAT(${params.xColumn},'%Y') ${params.xColumn}, sum(${params.yColumn}) total FROM xueshengchengji
 1=1 ${ew.sqlSegment}
group by DATE_FORMAT(${params.xColumn},'%Y')

mapper.select:
SELECT ${params.column} , count(1) total FROM xueshengchengji
 1=1 ${ew.sqlSegment}
group by ${params.column}
limit 10
